/**
 * @summary Upload a photo to a job
 */
export const getUploadPhotoUrl = (id: number) => {
  return `/api/jobs/${id}/photos`;
};

export const uploadPhoto = async (
  id: number,
  uploadPhotoInput: UploadPhotoInput,
  options?: RequestInit,
): Promise<Photo> => {
  return customFetch<Photo>(getUploadPhotoUrl(id), {
    ...options,
    method: "POST",
    headers: { "Content-Type": "application/json", ...options?.headers },
    body: JSON.stringify(uploadPhotoInput),
  });
};

export const getUploadPhotoMutationOptions = <
  TError = ErrorType<unknown>,
  TContext = unknown,
>(options?: {
  mutation?: UseMutationOptions<
    Awaited<ReturnType<typeof uploadPhoto>>,
    TError,
    { id: number; data: BodyType<UploadPhotoInput> },
    TContext
  >;
  request?: SecondParameter<typeof customFetch>;
}): UseMutationOptions<
  Awaited<ReturnType<typeof uploadPhoto>>,
  TError,
  { id: number; data: BodyType<UploadPhotoInput> },
  TContext
> => {
  const mutationKey = ["uploadPhoto"];
  const { mutation: mutationOptions, request: requestOptions } = options
    ? options.mutation &&
      "mutationKey" in options.mutation &&
      options.mutation.mutationKey
      ? options
      : { ...options, mutation: { ...options.mutation, mutationKey } }
    : { mutation: { mutationKey }, request: undefined };

  const mutationFn: MutationFunction<
    Awaited<ReturnType<typeof uploadPhoto>>,
    { id: number; data: BodyType<UploadPhotoInput> }
  > = (props) => {
    const { id, data } = props ?? {};

    return uploadPhoto(id, data, requestOptions);
  };

  return { mutationFn, ...mutationOptions };
};

